    if (!running) return;
    if (!lastTs) lastTs = ts;
    const dt = (ts - lastTs) / 1e3;
    lastTs = ts;
    if (!(cycleHeight > 0) || !allMetrics.length) {
      measure();
      rafId = requestAnimationFrame(frame);
      return;
    }
