    normalizePos();
    track.style.transform = "translate3d(0, " + -pos + "px, 0)";
    setActiveByCenter();
    updateItemVisuals();
    rafId = requestAnimationFrame(frame);
  };
  const start = () => {
    if (running) return;
    running = true;
    lastTs = 0;
    rafId = requestAnimationFrame(frame);
  };
  const stop = () => {
    running = false;
    if (rafId) cancelAnimationFrame(rafId);
    rafId = null;
  };
